initial_candidates.sql:
SELECT COUNT(*) 
FROM Patient p
LEFT JOIN Examination e ON p.ID = e.ID
WHERE e.ID IS NULL 
   OR (e.Examination Date IS NOT NULL 
       AND (
           strftime('%Y', e.Examination Date) - strftime('%Y', p.First Date) > 1 
           OR (
               strftime('%Y', e.Examination Date) - strftime('%Y', p.First Date) = 1 
               AND (
                   strftime('%m', e.Examination Date) > strftime('%m', p.First Date) 
                   OR (
                       strftime('%m', e.Examination Date) = strftime('%m', p.First Date) 
                       AND strftime('%d', e.Examination Date) >= strftime('%d', p.First Date)
                   )
               )
           )
       )
   );
